var residuals = function(probs) {
  if (probs.length === 0) {
    return [];
  } else {
    var p = probs[0];
    var rest = probs.slice(1);
    var restSum = rest.reduce(function(a, b) { return a + b; }, 0);
    var residual = restSum === 0 ? 1 : p / (p + restSum);
    return [residual].concat(residuals(rest));
  }
};

print(residuals([0.2, 0.3, 0.1, 0.4]));

var sampleDiscrete = function(residuals, i) {
  if(flip(first(residuals))) {
    return i;
  } else {
    return sampleDiscrete(rest(residuals), i + 1);
  }
};

var myDiscrete = function(probs) {
  return sampleDiscrete(residuals(probs), 0);
};

viz(Infer({method: 'forward', samples: 10000}, function() {
  return myDiscrete([0.2, 0.3, 0.1, 0.4]);
}));

