// a source of reusable state symbols
var getState = DPmem(1, uuid);

// transition model: for each state, a DPmem'd transition function
var transition = mem(function(state) {
  return DPmem(1, getState);
});

// run the HMM for n steps
var sampleStates = function(state, n) {
  if (n == 0) {
    return [];
  } else {
    var nextState = transition(state)();
    return [nextState].concat(sampleStates(nextState, n - 1));
  }
};

