var people = ['tom', 'fred', 'jim', 'lisa', 'mary', 'sue'];
var talks = [['tom', 'fred'], ['tom', 'jim'], ['fred', 'jim'],
             ['lisa', 'mary'], ['lisa', 'sue'], ['mary', 'sue']];
var doesNotTalk = [['tom', 'lisa'], ['fred', 'mary'], ['jim', 'sue']];

var results = Infer({method: 'MCMC', samples: 10000}, function() {
  // Each person is assigned to a class
  var getClass = DPmem(1, uuid);
  var personToClass = mem(function(person) { return getClass() });

  // The probability of talking depends on the pair of classes
  var classPairToTalkProb = mem(function(class1, class2) { return beta(1, 1) });
  var talkProb = function(person1, person2) {
    return classPairToTalkProb(personToClass(person1), personToClass(person2));
  };

  // Observe the talking pairs
  map(function(pair) {
    factor(Bernoulli({p: talkProb(pair[0], pair[1])}).score(true));
  }, talks);

  // Observe the non-talking pairs
  map(function(pair) {
    factor(Bernoulli({p: talkProb(pair[0], pair[1])}).score(false));
  }, doesNotTalk);

  return {
    sameClassTomFred: personToClass('tom') == personToClass('fred'),
    sameClassTomLisa: personToClass('tom') == personToClass('lisa'),
    sameClassLisaMary: personToClass('lisa') == personToClass('mary')
  };
});

viz.marginals(results);

