// CrossCat: features cluster into kinds, objects cluster within each kind
// Foods x Features example
var foods = ['eggs', 'lobster', 'oatmeal', 'steak', 'milk', 'bread'];
var features = ['dairy', 'expensive', 'breakfast', 'dinner', 'animal-based'];

// Each feature belongs to a "kind" (view)
var featureToKind = mem(function(feature) {
  return kindDistribution();
});
var kindDistribution = DPmem(1, uuid);

// Within each kind, each object belongs to a category
var objectToCategory = mem(function(food, kind) {
  return categoryDistribution(kind)();
});
var categoryDistribution = mem(function(kind) {
  return DPmem(1, uuid);
});

// Each (kind, category) pair has a distribution over feature presence
var categoryFeatureWeight = mem(function(kind, category) {
  return beta(1, 1);
});

// Generate a feature value for a food
var generateFeature = function(food, feature) {
  var kind = featureToKind(feature);
  var category = objectToCategory(food, kind);
  return flip(categoryFeatureWeight(kind, category));
};

// Sample a cross-cat table
var sampleCrossCat = function() {
  return map(function(food) {
    return {food: food,
            features: map(function(feature) {
              return generateFeature(food, feature);
            }, features)};
  }, foods);
};

