// Goldwater Model 1: Unsupervised word segmentation using a DP
// Adapted from Goldwater 2009

///fold:
var pickStick = function(sticks, J) {
  return flip(sticks(J)) ? J : pickStick(sticks, J+1);  
};

var makeSticks = function(alpha) {
  var sticks = mem(function(index) {return beta(1, alpha)});
  return function() {
    return pickStick(sticks,1)
  };
}

var DPmem = function(alpha, baseDist) {
  var augmentedProc = mem(function(args, stickIndex) {return apply(baseDist, args)});
  var DP = mem(function(args) {return makeSticks(alpha)});
  return function(argsin) {
    var stickIndex = DP(argsin)()
    return augmentedProc(argsin, stickIndex);
  }
}
///

// The phonemes in our toy language
var phonemes = ['a', 'b', 'i', 't', 'u'];

// A random word is a sequence of phonemes
var randomWord = function() {
  var len = randomInteger(4) + 1;
  return repeat(len, function() { return uniformDraw(phonemes) }).join('');
};

// Use DPmem to create a lexicon: reusable words drawn from randomWord
var getWord = DPmem(1, randomWord);

// Generate a sentence as a sequence of words
var sampleSentence = function(nWords) {
  return repeat(nWords, getWord).join(' ');
};

print("Sample sentences from the model:");
repeat(5, function() { print(sampleSentence(4)); });

// Show the reuse property: words tend to repeat
print("\nSample words (showing reuse):");
viz(repeat(100, getWord));
