var ___ = ' '; 
var D = { name: 'Donut' };

var grid = [
  ['___', '___', '___', '___',  D]
];

var mdp = makeGridWorldMDP({ grid, start: [0, 0] });

var transition = function(state, action) {
  return state + action;
};

var utility = function(state) {
  if (state === 4) {
    return 1;
  } else {
    return 0;
  }
};

var makeAgent = function() { 

  var act = function(state, timeLeft) {
    return Infer({ model() {
      var action = uniformDraw([-1, 0, 1]);
      var eu = expectedUtility(state, action, timeLeft);
      factor(100 * eu);
      return action;
    }});
  };

  var expectedUtility = function(state, action, timeLeft){
    var u = utility(state, action);
    var newTimeLeft = timeLeft - 1;
    if (newTimeLeft === 0){
      return u; 
    } else {
      return u + expectation(Infer({ model() {
        var nextState = transition(state, action); 
        var nextAction = sample(act(nextState, newTimeLeft));
        return expectedUtility(nextState, nextAction, newTimeLeft);
      }}));
    }
  };

  return { act };
}

var simulate = function(startState, totalTime) {
  var act = makeAgent().act;

  var helper = function(state, timeLeft, trajectory) {
    if (timeLeft === 0) {
      return trajectory;
    } else {
      var action = sample(act(state, timeLeft));
      var nextState = transition(state, action);
      return helper(nextState, timeLeft - 1, trajectory.concat(nextState));
    }
  };

  return helper(startState, totalTime, [startState]);
};

var startState = 0;
var totalTime = 5;

var trajectory = simulate(startState, totalTime);
print("Agent's trajectory: " + trajectory);
